import{_ as i,o as e,c as l,a0 as o}from"./chunks/framework.CSGB4SNl.js";const g=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"java/eight-legged essay/八股文-简历补充.md","filePath":"java/eight-legged essay/八股文-简历补充.md"}'),t={name:"java/eight-legged essay/八股文-简历补充.md"};function r(n,a,p,h,c,d){return e(),l("div",null,[...a[0]||(a[0]=[o('<h4 id="linux常用命令" tabindex="-1">linux常用命令 <a class="header-anchor" href="#linux常用命令" aria-label="Permalink to &quot;linux常用命令&quot;">​</a></h4><ol><li>常用的话有查看进程ps -ef | grep java，看日志tail -f，查看端口占用netstat -tuln | grep 8080，tar/zip解压缩，编辑文件vi/vim，chmod/chown， 看权限改权限，kill 杀进程</li></ol><h4 id="git常用命令" tabindex="-1">git常用命令 <a class="header-anchor" href="#git常用命令" aria-label="Permalink to &quot;git常用命令&quot;">​</a></h4><ol><li>常用的就是git clone克隆仓库，git add添加到暂存区，git pull拉取、git pull推送远程、git commit提交</li><li>git branch name创建新分支、git checkout切换到指定分支，git branch 查看所有分支</li></ol><h4 id="什么是rag" tabindex="-1">什么是RAG <a class="header-anchor" href="#什么是rag" aria-label="Permalink to &quot;什么是RAG&quot;">​</a></h4><ol><li>检索增强生成，就是一个人为建立的知识库，在生成回答前先在指定文档库进行查找，就是一个向量数据库</li></ol><h4 id="springboot的启动流程" tabindex="-1">SpringBoot的启动流程 <a class="header-anchor" href="#springboot的启动流程" aria-label="Permalink to &quot;SpringBoot的启动流程&quot;">​</a></h4><ol><li><p>main方法启动创建SpringApplication对象，调用其run方法执行下面步骤</p></li><li><p>SpringBoot会先检查是web应用还是其它应用，然后预先加载所有要用到的初始化器和监听器存起来</p></li><li><p>然后就将yml配置文件、环境变量、命令行参数等都加载好</p></li><li><p>根据第一步确定的类型初始化一个空的Bean容器</p></li><li><p>刷新容器，解析@SpringBootApplication，加载扫描所有Bean，执行自动配置把所有组件注册到容器中，最后发布启动完成事件通知所有监听器，刷新完成后就自启动tomcat服务器-如果是web应用</p></li><li><p>执行回调，看下也没有继承了命令行执行器类的Bean，有就执行里面的run方法</p></li><li><p>至此就启动完成</p></li></ol><h4 id="springboot的自动配置" tabindex="-1">SpringBoot的自动配置 <a class="header-anchor" href="#springboot的自动配置" aria-label="Permalink to &quot;SpringBoot的自动配置&quot;">​</a></h4><ol><li>会基于@EnableAutoConfiguration，这个注解通过@import导入一个类，这个类会扫描META-INF下面的Spring配置文件，这里面定义了所有自动配置类，根据这些配置类上面的条件注解来加载</li><li>要禁用某些自动配置的话可以在@SpringBootApplication上面的exclude参数进行排除具体的自动配置类</li></ol><h4 id="什么是死信队列" tabindex="-1">什么是死信队列 <a class="header-anchor" href="#什么是死信队列" aria-label="Permalink to &quot;什么是死信队列&quot;">​</a></h4><ol><li>就是指消息队列中无法被正常消费的消息，为啥出现：消费者直接拒绝了-且不重新入队、超过过期时间ttl、超过队列最大长度-最早的消息会被移除标记成死信</li></ol><h4 id="什么是docker-是怎么使用的-你在项目中是如何使用的" tabindex="-1">什么是docker，是怎么使用的，你在项目中是如何使用的 <a class="header-anchor" href="#什么是docker-是怎么使用的-你在项目中是如何使用的" aria-label="Permalink to &quot;什么是docker，是怎么使用的，你在项目中是如何使用的&quot;">​</a></h4><ol><li>docker是一种容器化技术，可以将应用和依赖打包成一个镜像，在任意环境都能一键运行，项目中我是通过配置docker-compose配置文件将mysql、redis、springboot应用打包成一个镜像，然后将容器内端口映射到宿主机的端口，并对外开放</li></ol><h4 id="" tabindex="-1"><a class="header-anchor" href="#" aria-label="Permalink to &quot;&quot;">​</a></h4>',15)])])}const u=i(t,[["render",r]]);export{g as __pageData,u as default};
